import React, { useState } from 'react';
import { animated, useSpring } from 'react-spring';
import { X, ArrowLeft, Heart, Clock, Paperclip, Send } from 'lucide-react';
import useNudgeStore from '../../store/nudgeStore';

const SecondaryBottomSheet = () => {
  const { 
    isLeftPanelOpen, 
    selectedNudgeId, 
    nudges, 
    hasNewNudge, 
    newNudgeId,
    closeLeftPanel, 
    markAsRead,
    setSelectedNudge,
    clearNewNudgeNotification
  } = useNudgeStore();

  const [replyText, setReplyText] = useState('');
  const [showReschedule, setShowReschedule] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedDate, setSelectedDate] = useState('');
  const [selectedTimeRange, setSelectedTimeRange] = useState('');

  // Determinar qual nudge mostrar
  const currentNudge = selectedNudgeId 
    ? nudges.find(n => n.id === selectedNudgeId)
    : newNudgeId 
    ? nudges.find(n => n.id === newNudgeId)
    : null;

  // Determinar se deve mostrar (painel aberto OU nova nudge em modo compactado)
  const shouldShow = isLeftPanelOpen || hasNewNudge;
  const isCompactMode = hasNewNudge && !isLeftPanelOpen;

  // Animação do container
  const containerAnimation = useSpring({
    transform: shouldShow ? 'translateX(0%)' : 'translateX(-100%)',
    opacity: shouldShow ? 1 : 0,
    height: isCompactMode ? '80px' : '500px',
    config: { tension: 300, friction: 30 }
  });

  // Função para expandir do modo compactado
  const expandFromCompact = () => {
    if (newNudgeId) {
      setSelectedNudge(newNudgeId);
      clearNewNudgeNotification();
      markAsRead(newNudgeId);
    }
  };

  // Função para enviar resposta
  const handleSendReply = () => {
    if (replyText.trim()) {
      console.log('Sending reply:', replyText);
      setReplyText('');
    }
  };

  // Função para reagendar
  const handleReschedule = () => {
    if (selectedDate && selectedTimeRange) {
      setShowSuccess(true);
      setTimeout(() => {
        setShowSuccess(false);
        setShowReschedule(false);
        setSelectedDate('');
        setSelectedTimeRange('');
      }, 2000);
    }
  };

  if (!shouldShow || !currentNudge) {
    return null;
  }

  return (
    <div className="fixed bottom-6 left-6 z-50">
      <animated.div
        style={{
          ...containerAnimation,
          width: '380px'
        }}
        className="bg-neutral-800 border border-neutral-700 shadow-2xl rounded-2xl overflow-hidden"
      >
        <div className="p-4 flex flex-col h-full">
          {isCompactMode ? (
            /* Modo Compactado - Nova Nudge */
            <div 
              className="flex items-center justify-between cursor-pointer"
              onClick={expandFromCompact}
            >
              <div className="flex items-center space-x-3">
                <div className="relative">
                  <img
                    src={currentNudge.sender.avatar}
                    alt={currentNudge.sender.name}
                    className="w-10 h-10 rounded-full"
                  />
                  <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-800 ${
                    currentNudge.sender.status === 'online' ? 'bg-green-500' : 
                    currentNudge.sender.status === 'away' ? 'bg-orange-500' : 'bg-gray-500'
                  }`} />
                </div>
                <div>
                  <h3 className="text-white font-medium">{currentNudge.sender.name}</h3>
                  <p className="text-neutral-400 text-sm truncate max-w-[200px]">
                    {currentNudge.message}
                  </p>
                </div>
                <div className="w-6 h-6 bg-red-500 rounded-full flex items-center justify-center">
                  <span className="text-white text-xs font-bold">!</span>
                </div>
              </div>
              <div className="flex items-center space-x-2">
                <ArrowLeft className="h-5 w-5 text-gray-400 transform rotate-90" />
              </div>
            </div>
          ) : (
            /* Modo Expandido - Visualização Completa */
            <>
              {/* Header */}
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-3">
                  <div className="relative">
                    <img
                      src={currentNudge.sender.avatar}
                      alt={currentNudge.sender.name}
                      className="w-10 h-10 rounded-full"
                    />
                    <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-800 ${
                      currentNudge.sender.status === 'online' ? 'bg-green-500' : 
                      currentNudge.sender.status === 'away' ? 'bg-orange-500' : 'bg-gray-500'
                    }`} />
                  </div>
                  <div>
                    <h2 className="text-lg font-semibold text-white">{currentNudge.sender.name}</h2>
                    <p className="text-neutral-400 text-sm">{currentNudge.timestamp}</p>
                  </div>
                </div>
                <button
                  onClick={closeLeftPanel}
                  className="p-2 text-gray-400 hover:text-white transition-colors"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>

              {/* Conteúdo */}
              <div className="flex-1 overflow-hidden">
                {showSuccess ? (
                  <div className="flex-1 flex items-center justify-center">
                    <div className="text-center">
                      <div className="w-16 h-16 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-4">
                        <Clock className="h-8 w-8 text-white" />
                      </div>
                      <h3 className="text-lg font-semibold text-white mb-2">Alternative Time Sent!</h3>
                      <p className="text-neutral-400 text-sm">Your alternative time has been sent successfully.</p>
                    </div>
                  </div>
                ) : showReschedule ? (
                  <div className="flex-1 flex flex-col">
                    <div className="flex items-center space-x-3 mb-4">
                      <button
                        onClick={() => setShowReschedule(false)}
                        className="p-1 text-gray-400 hover:text-white transition-colors"
                      >
                        <ArrowLeft className="h-5 w-5" />
                      </button>
                      <h3 className="text-lg font-semibold text-white">Suggest Alternative Time</h3>
                    </div>

                    <div className="space-y-4 flex-1">
                      <div>
                        <label className="block text-sm font-medium text-neutral-300 mb-2">
                          Select Date
                        </label>
                        <select
                          value={selectedDate}
                          onChange={(e) => setSelectedDate(e.target.value)}
                          className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                        >
                          <option value="">Choose a date</option>
                          <option value="tomorrow">Tomorrow</option>
                          <option value="next-week">Next Week</option>
                          <option value="next-month">Next Month</option>
                        </select>
                      </div>

                      <div>
                        <label className="block text-sm font-medium text-neutral-300 mb-2">
                          Time Range
                        </label>
                        <select
                          value={selectedTimeRange}
                          onChange={(e) => setSelectedTimeRange(e.target.value)}
                          className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                        >
                          <option value="">Choose time range</option>
                          <option value="morning">Morning (9:00 - 12:00)</option>
                          <option value="afternoon">Afternoon (13:00 - 17:00)</option>
                          <option value="evening">Evening (18:00 - 20:00)</option>
                        </select>
                      </div>

                      <button
                        onClick={handleReschedule}
                        disabled={!selectedDate || !selectedTimeRange}
                        className="w-full bg-white text-black py-2 px-4 rounded-lg font-medium hover:bg-gray-100 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                      >
                        Send Alternative Time
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="flex-1 flex flex-col">
                    {/* Mensagem Principal */}
                    <div className="bg-neutral-700 rounded-lg p-4 mb-4">
                      <div className="flex items-start justify-between mb-2">
                        <p className="text-white">{currentNudge.message}</p>
                        {currentNudge.priority === 'high' && (
                          <span className="bg-red-500 text-white text-xs px-2 py-1 rounded-full ml-2">
                            High Priority
                          </span>
                        )}
                      </div>

                      {currentNudge.attachments && currentNudge.attachments.length > 0 && (
                        <div className="flex items-center space-x-2 mt-3">
                          <Paperclip className="h-4 w-4 text-neutral-400" />
                          <span className="text-neutral-400 text-sm">
                            {currentNudge.attachments.length} attachment(s)
                          </span>
                        </div>
                      )}
                    </div>

                    {/* Histórico de Respostas */}
                    {currentNudge.replyHistory && currentNudge.replyHistory.length > 0 && (
                      <div className="mb-4">
                        <h4 className="text-neutral-300 text-sm font-medium mb-2">Previous replies</h4>
                        <div className="space-y-2">
                          {currentNudge.replyHistory.map((reply, index) => (
                            <div key={index} className="bg-neutral-700 rounded-lg p-3">
                              <p className="text-white text-sm">{reply.message}</p>
                              <p className="text-neutral-400 text-xs mt-1">{reply.timestamp}</p>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Campo de Resposta */}
                    <div className="mt-auto">
                      <div className="flex space-x-2 mb-3">
                        <button
                          onClick={handleSendReply}
                          className="flex-1 bg-white text-black py-2 px-4 rounded-lg font-medium hover:bg-gray-100 transition-colors"
                        >
                          Reply
                        </button>
                        <button
                          onClick={() => setShowReschedule(true)}
                          className="flex-1 bg-neutral-600 text-white py-2 px-4 rounded-lg font-medium hover:bg-neutral-500 transition-colors"
                        >
                          Won't be able
                        </button>
                        <button className="p-2 bg-neutral-600 text-white rounded-lg hover:bg-neutral-500 transition-colors">
                          <Heart className="h-5 w-5" />
                        </button>
                      </div>

                      <div className="flex space-x-2">
                        <input
                          type="text"
                          value={replyText}
                          onChange={(e) => setReplyText(e.target.value)}
                          placeholder="Type your reply..."
                          className="flex-1 bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white placeholder-neutral-400 focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                          onKeyPress={(e) => e.key === 'Enter' && handleSendReply()}
                        />
                        <button
                          onClick={handleSendReply}
                          className="p-2 bg-white text-black rounded-lg hover:bg-gray-100 transition-colors"
                        >
                          <Send className="h-5 w-5" />
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </>
          )}
        </div>
      </animated.div>
    </div>
  );
};

export default SecondaryBottomSheet;
